const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const https = require('https');
const result = await new Promise((resolve) => {
  https.get({
    hostname: 'bliybylxjwemgzjvazyc.supabase.co',
    path: '/storage/v1/object/review/confirm-queue.json',
    headers: { Authorization: `Bearer ${SUPABASE_KEY}` },
  }, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => resolve({ status: res.statusCode, body: data }));
  }).on('error', () => resolve({ status: 0, body: '' }));
});
let queue = { jobs: [] };
if (result.status === 200) {
  try { queue = JSON.parse(result.body); } catch (e) { /* keep empty */ }
}
return [{ json: queue }];

const queue = $json;
const fs = require('fs');
const { execSync } = require('child_process');
const repoDir = '/Users/agent/Desktop/Mine/9. Coding/Claude Code/100_Todo/projects/stock-dashboard';
const filePath = `${repoDir}/data/concept-sectors.json`;

// 安全檢查：這個檔案若已經有未 commit 的異動（可能是別的 session 正在改），本輪跳過，避免蓋掉別人的工作
const status = execSync('git status --porcelain data/concept-sectors.json', { cwd: repoDir }).toString().trim();
if (status) {
  return [{ json: { skipped: true, reason: 'concept-sectors.json 有未 commit 的異動，本輪跳過', gitStatus: status } }];
}

const data = JSON.parse(fs.readFileSync(filePath, 'utf-8'));

for (const job of (queue.jobs || [])) {
  for (const item of job.items) {
    if (!item.concepts || item.concepts.length === 0) {
      delete data.stocks[item.code];
    } else {
      data.stocks[item.code] = item.concepts;
      for (const c of item.concepts) {
        if (!data.concepts[c]) data.concepts[c] = { desc: '' };
      }
    }
  }
}

const dateStr = new Date().toISOString().slice(0, 10);
const seq = (data.version || '').startsWith(dateStr) ? parseInt(data.version.split('.')[1] || '0', 10) + 1 : 1;
data.version = `${dateStr}.${seq}`;
data.updatedAt = dateStr;

const payload = JSON.stringify(data, null, 2);
fs.writeFileSync(filePath, payload);

// R3：本機 iCloud Drive 曾經在寫檔後的短暫時間窗把內容悄悄還原成舊版（2026-07-10 弄壞過一次
// production），寫完立刻回讀比對，不一致就中止，不 commit 壞資料
const verify = fs.readFileSync(filePath, 'utf-8');
if (verify !== payload) {
  return [{ json: { error: true, message: 'iCloud 干擾：寫入後回讀不一致，本輪中止（未 commit）' } }];
}

const jobIds = (queue.jobs || []).map(j => j.id);
try {
  execSync(`git add data/concept-sectors.json && git commit -m "chore: review 頁面確認概念分類更新 (jobs: ${jobIds.join(',')})" && git push`, { cwd: repoDir });
} catch (e) {
  return [{ json: { error: true, message: 'git commit/push 失敗：' + e.message } }];
}

return [{ json: { processed: (queue.jobs || []).length, version: data.version, jobIds } }];

const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const https = require('https');
const processedIds = new Set($json.jobIds || []);

function getQueue() {
  return new Promise((resolve) => {
    https.get({
      hostname: 'bliybylxjwemgzjvazyc.supabase.co',
      path: '/storage/v1/object/review/confirm-queue.json',
      headers: { Authorization: `Bearer ${SUPABASE_KEY}` },
    }, (res) => {
      let body = '';
      res.on('data', d => body += d);
      res.on('end', () => { try { resolve(JSON.parse(body)); } catch (e) { resolve({ jobs: [] }); } });
    }).on('error', () => resolve({ jobs: [] }));
  });
}

const current = await getQueue();
const remaining = (current.jobs || []).filter(j => !processedIds.has(j.id));

const body = JSON.stringify({ jobs: remaining });
await new Promise((resolve) => {
  const req = https.request({
    hostname: 'bliybylxjwemgzjvazyc.supabase.co',
    path: '/storage/v1/object/review/confirm-queue.json',
    method: 'POST',
    headers: {
      Authorization: `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body),
      'x-upsert': 'true',
    },
  }, (res) => { res.on('data', () => {}); res.on('end', resolve); });
  req.on('error', resolve);
  req.write(body);
  req.end();
});
return [{ json: { cleared: true, remaining: remaining.length } }];
